package pe.org.camaracomercioica.protestos.controller; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import pe.org.camaracomercioica.protestos.dto.UploadResponse; import pe.org.camaracomercioica.protestos.service.UploadService; import java.io.IOException; @RestController @RequiredArgsConstructor public class UploadController {private final UploadService service;@PostMapping(value="/api/documentos/upload",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) @ResponseStatus(HttpStatus.CREATED) UploadResponse documento(@RequestParam Long solicitudId,@RequestPart MultipartFile file,Authentication auth)throws IOException{var staff=auth.getAuthorities().stream().anyMatch(a->a.getAuthority().equals("ROLE_ADMIN")||a.getAuthority().equals("ROLE_ANALISTA"));return service.documento(solicitudId,file,auth.getName(),staff);}@PostMapping(value="/api/excel/upload",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) @ResponseStatus(HttpStatus.CREATED) UploadResponse excel(@RequestPart MultipartFile file,Authentication a)throws IOException{return service.excel(file,a.getName());}}
